import React, { useState } from 'react';
import { Package, Send, MapPin, Search, User, Calendar, DollarSign, Clock, CheckCircle, XCircle, Truck } from 'lucide-react';

export default function PostOfficeApp() {
  const [activeTab, setActiveTab] = useState('track');
  const [trackingNumber, setTrackingNumber] = useState('');
  const [searchResult, setSearchResult] = useState(null);

  // Sample data for demonstration
  const sampleParcels = [
    { id: 'PKG001', sender: 'Rajesh Kumar', receiver: 'Priya Sharma', status: 'In Transit', from: 'Delhi', to: 'Mumbai', weight: '2.5kg', cost: '₹150' },
    { id: 'PKG002', sender: 'Amit Singh', receiver: 'Neha Verma', status: 'Delivered', from: 'Bangalore', to: 'Pune', weight: '1.2kg', cost: '₹100' },
    { id: 'PKG003', sender: 'Suresh Patel', receiver: 'Kavita Joshi', status: 'Pending', from: 'Ahmedabad', to: 'Surat', weight: '3.0kg', cost: '₹200' }
  ];

  const [parcels, setParcels] = useState(sampleParcels);
  const [newParcel, setNewParcel] = useState({
    sender: '',
    receiver: '',
    from: '',
    to: '',
    weight: '',
    cost: ''
  });

  const handleTrack = () => {
    const found = parcels.find(p => p.id === trackingNumber.toUpperCase());
    setSearchResult(found || { error: 'Parcel not found' });
  };

  const handleAddParcel = (e) => {
    e.preventDefault();
    const newId = `PKG${String(parcels.length + 1).padStart(3, '0')}`;
    const parcel = {
      id: newId,
      ...newParcel,
      status: 'Pending'
    };
    setParcels([...parcels, parcel]);
    setNewParcel({ sender: '', receiver: '', from: '', to: '', weight: '', cost: '' });
    alert(`Parcel registered successfully! Tracking ID: ${newId}`);
  };

  const getStatusIcon = (status) => {
    switch(status) {
      case 'Delivered': return <CheckCircle className="text-green-500" size={20} />;
      case 'In Transit': return <Truck className="text-blue-500" size={20} />;
      case 'Pending': return <Clock className="text-yellow-500" size={20} />;
      default: return <XCircle className="text-red-500" size={20} />;
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100">
      {/* Header */}
      <header className="bg-indigo-600 text-white shadow-lg">
        <div className="container mx-auto px-4 py-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-3">
              <Package size={36} />
              <div>
                <h1 className="text-3xl font-bold">Dakkhana</h1>
                <p className="text-indigo-200 text-sm">Post Office Management System</p>
              </div>
            </div>
            <div className="flex items-center space-x-2">
              <User size={24} />
              <span>Admin</span>
            </div>
          </div>
        </div>
      </header>

      {/* Navigation Tabs */}
      <div className="container mx-auto px-4 mt-6">
        <div className="bg-white rounded-lg shadow-md p-2 flex space-x-2">
          <button
            onClick={() => setActiveTab('track')}
            className={`flex-1 py-3 px-4 rounded-md flex items-center justify-center space-x-2 transition ${
              activeTab === 'track' ? 'bg-indigo-600 text-white' : 'hover:bg-gray-100'
            }`}
          >
            <Search size={20} />
            <span>Track Parcel</span>
          </button>
          <button
            onClick={() => setActiveTab('register')}
            className={`flex-1 py-3 px-4 rounded-md flex items-center justify-center space-x-2 transition ${
              activeTab === 'register' ? 'bg-indigo-600 text-white' : 'hover:bg-gray-100'
            }`}
          >
            <Send size={20} />
            <span>Register Parcel</span>
          </button>
          <button
            onClick={() => setActiveTab('list')}
            className={`flex-1 py-3 px-4 rounded-md flex items-center justify-center space-x-2 transition ${
              activeTab === 'list' ? 'bg-indigo-600 text-white' : 'hover:bg-gray-100'
            }`}
          >
            <Package size={20} />
            <span>All Parcels</span>
          </button>
        </div>
      </div>

      {/* Main Content */}
      <div className="container mx-auto px-4 py-8">
        {/* Track Parcel Tab */}
        {activeTab === 'track' && (
          <div className="bg-white rounded-lg shadow-md p-8">
            <h2 className="text-2xl font-bold mb-6 text-gray-800">Track Your Parcel</h2>
            <div className="flex space-x-4 mb-6">
              <input
                type="text"
                placeholder="Enter Tracking Number (e.g., PKG001)"
                value={trackingNumber}
                onChange={(e) => setTrackingNumber(e.target.value)}
                className="flex-1 px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
              />
              <button
                onClick={handleTrack}
                className="bg-indigo-600 text-white px-8 py-3 rounded-lg hover:bg-indigo-700 transition flex items-center space-x-2"
              >
                <Search size={20} />
                <span>Track</span>
              </button>
            </div>

            {searchResult && (
              <div className="mt-6 p-6 bg-gray-50 rounded-lg border border-gray-200">
                {searchResult.error ? (
                  <div className="flex items-center space-x-2 text-red-600">
                    <XCircle size={24} />
                    <span className="text-lg">{searchResult.error}</span>
                  </div>
                ) : (
                  <div>
                    <div className="flex items-center justify-between mb-4">
                      <h3 className="text-xl font-bold text-gray-800">Tracking ID: {searchResult.id}</h3>
                      <div className="flex items-center space-x-2">
                        {getStatusIcon(searchResult.status)}
                        <span className="font-semibold">{searchResult.status}</span>
                      </div>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="flex items-center space-x-2">
                        <User size={18} className="text-gray-500" />
                        <div>
                          <p className="text-sm text-gray-500">Sender</p>
                          <p className="font-semibold">{searchResult.sender}</p>
                        </div>
                      </div>
                      <div className="flex items-center space-x-2">
                        <User size={18} className="text-gray-500" />
                        <div>
                          <p className="text-sm text-gray-500">Receiver</p>
                          <p className="font-semibold">{searchResult.receiver}</p>
                        </div>
                      </div>
                      <div className="flex items-center space-x-2">
                        <MapPin size={18} className="text-gray-500" />
                        <div>
                          <p className="text-sm text-gray-500">From</p>
                          <p className="font-semibold">{searchResult.from}</p>
                        </div>
                      </div>
                      <div className="flex items-center space-x-2">
                        <MapPin size={18} className="text-gray-500" />
                        <div>
                          <p className="text-sm text-gray-500">To</p>
                          <p className="font-semibold">{searchResult.to}</p>
                        </div>
                      </div>
                      <div className="flex items-center space-x-2">
                        <Package size={18} className="text-gray-500" />
                        <div>
                          <p className="text-sm text-gray-500">Weight</p>
                          <p className="font-semibold">{searchResult.weight}</p>
                        </div>
                      </div>
                      <div className="flex items-center space-x-2">
                        <DollarSign size={18} className="text-gray-500" />
                        <div>
                          <p className="text-sm text-gray-500">Cost</p>
                          <p className="font-semibold">{searchResult.cost}</p>
                        </div>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        )}

        {/* Register Parcel Tab */}
        {activeTab === 'register' && (
          <div className="bg-white rounded-lg shadow-md p-8">
            <h2 className="text-2xl font-bold mb-6 text-gray-800">Register New Parcel</h2>
            <form onSubmit={handleAddParcel}>
              <div className="grid grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Sender Name</label>
                  <input
                    type="text"
                    required
                    value={newParcel.sender}
                    onChange={(e) => setNewParcel({...newParcel, sender: e.target.value})}
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                    placeholder="Enter sender name"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Receiver Name</label>
                  <input
                    type="text"
                    required
                    value={newParcel.receiver}
                    onChange={(e) => setNewParcel({...newParcel, receiver: e.target.value})}
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                    placeholder="Enter receiver name"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">From (City)</label>
                  <input
                    type="text"
                    required
                    value={newParcel.from}
                    onChange={(e) => setNewParcel({...newParcel, from: e.target.value})}
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                    placeholder="Source city"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">To (City)</label>
                  <input
                    type="text"
                    required
                    value={newParcel.to}
                    onChange={(e) => setNewParcel({...newParcel, to: e.target.value})}
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                    placeholder="Destination city"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Weight</label>
                  <input
                    type="text"
                    required
                    value={newParcel.weight}
                    onChange={(e) => setNewParcel({...newParcel, weight: e.target.value})}
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                    placeholder="e.g., 2.5kg"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Cost</label>
                  <input
                    type="text"
                    required
                    value={newParcel.cost}
                    onChange={(e) => setNewParcel({...newParcel, cost: e.target.value})}
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                    placeholder="e.g., ₹150"
                  />
                </div>
              </div>
              <button
                type="submit"
                className="mt-6 bg-indigo-600 text-white px-8 py-3 rounded-lg hover:bg-indigo-700 transition flex items-center space-x-2"
              >
                <Send size={20} />
                <span>Register Parcel</span>
              </button>
            </form>
          </div>
        )}

        {/* All Parcels Tab */}
        {activeTab === 'list' && (
          <div className="bg-white rounded-lg shadow-md p-8">
            <h2 className="text-2xl font-bold mb-6 text-gray-800">All Parcels</h2>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">Tracking ID</th>
                    <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">Sender</th>
                    <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">Receiver</th>
                    <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">Route</th>
                    <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">Weight</th>
                    <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">Cost</th>
                    <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-200">
                  {parcels.map((parcel) => (
                    <tr key={parcel.id} className="hover:bg-gray-50">
                      <td className="px-4 py-3 text-sm font-medium text-indigo-600">{parcel.id}</td>
                      <td className="px-4 py-3 text-sm">{parcel.sender}</td>
                      <td className="px-4 py-3 text-sm">{parcel.receiver}</td>
                      <td className="px-4 py-3 text-sm">{parcel.from} → {parcel.to}</td>
                      <td className="px-4 py-3 text-sm">{parcel.weight}</td>
                      <td className="px-4 py-3 text-sm">{parcel.cost}</td>
                      <td className="px-4 py-3">
                        <div className="flex items-center space-x-2">
                          {getStatusIcon(parcel.status)}
                          <span className="text-sm font-medium">{parcel.status}</span>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
